#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json
import sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")

    # Block bare `pnpm test` that doesn't include `test:ci`
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd:
        print(
            "Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and won't return.",
            file=sys.stderr,
        )
        return 2

    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Write/Edit on Python files, run ruff format then ruff check and surface errors."""
import json, subprocess, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool not in ("Write", "Edit"):
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Run ruff format first
    try:
        subprocess.run(
            ["ruff", "format", file_path],
            capture_output=True,
            timeout=10,
            cwd=os.environ.get("CLAUDE_PROJECT_DIR", ".")
        )
    except Exception:
        pass  # format failure is not blocking

    # Run ruff check and capture errors
    try:
        result = subprocess.run(
            ["ruff", "check", file_path],
            capture_output=True,
            text=True,
            timeout=10,
            cwd=os.environ.get("CLAUDE_PROJECT_DIR", ".")
        )
        if result.returncode != 0 and result.stdout.strip():
            errors = result.stdout.strip().splitlines()[:15]
            print(f"REQUIRED FOLLOW-UP: ruff check found {len(errors)} issue(s) in {file_path}:", file=sys.stderr)
            for err in errors:
                print(f"  {err}", file=sys.stderr)
            print("Fix each issue, then re-run ruff check. Do not stop. Do not ask.", file=sys.stderr)
            return 2
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit on a line that defines an exported identifier, grep
for all references and feed the list back to Claude for verification."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}

    # Handle both Edit and MultiEdit
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    names = set()
    for e in edits:
        for s in (e.get("old_string", ""), e.get("new_string", "")):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))

    if not names:
        return 0

    # Grep for each exported identifier
    for name in names:
        try:
            r = subprocess.run(
                ["grep", "-rn", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", name, "."],
                capture_output=True, text=True, timeout=5, cwd=ev.get("cwd", ".")
            )
            hits = [line for line in r.stdout.splitlines() if line][:30]
            if hits:
                print(f"REQUIRED FOLLOW-UP: export `{name}` was edited. {len(hits)} reference(s) found:", file=sys.stderr)
                for h in hits:
                    print(f"  {h}", file=sys.stderr)
                print("Update each reference to match the new value. Do not stop until all are verified.", file=sys.stderr)
                return 2
        except Exception:
            pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block Write/Edit operations that contain API keys or other secrets."""
import json, re, sys

# Patterns for common secret formats
SECRET_PATTERNS = [
    r'sk-[a-zA-Z0-9]{20,}',  # OpenAI, Anthropic API keys
    r'["\']?api[_-]?key["\']?\s*[:=]\s*["\'][^"\']{16,}["\']',
    r'["\']?secret[_-]?key["\']?\s*[:=]\s*["\'][^"\']{16,}["\']',
    r'["\']?password["\']?\s*[:=]\s*["\'][^"\']{8,}["\']',
    r'["\']?token["\']?\s*[:=]\s*["\'][^"\']{16,}["\']',
    r'Bearer\s+[a-zA-Z0-9_\-\.]{20,}',
]

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool not in ("Write", "Edit"):
        return 0

    content = ""
    if tool == "Write":
        content = inp.get("content", "")
    elif tool == "Edit":
        content = inp.get("new_string", "")

    for pattern in SECRET_PATTERNS:
        if re.search(pattern, content, re.IGNORECASE):
            print("BLOCKED: Detected potential API key or secret in file content. CLAUDE.md requires secrets come from process.env, never hardcoded. Read from environment variables instead.", file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

