#!/usr/bin/env python3
"""After Edit/Write on Python files, run py_compile to catch undefined variables
and syntax errors, feeding results back to Claude."""
import json, subprocess, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "Write"):
        return 0

    inp = ev.get("tool_input") or {}
    file_path = inp.get("file_path", "")

    if not file_path.endswith(".py"):
        return 0

    if not os.path.exists(file_path):
        return 0

    try:
        result = subprocess.run(
            ["python", "-m", "py_compile", file_path],
            capture_output=True,
            text=True,
            timeout=10,
            cwd=os.path.dirname(file_path) or "."
        )

        if result.returncode != 0:
            stderr = result.stderr.strip()
            print(f"BLOCKING: Python compilation failed for {file_path}:", file=sys.stderr)
            print(stderr, file=sys.stderr)
            print("Fix each error, then proceed. Do not stop. Do not ask.", file=sys.stderr)
            return 2

    except subprocess.TimeoutExpired:
        print(f"BLOCKING: py_compile timeout on {file_path}. Fix syntax errors.", file=sys.stderr)
        return 2
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())
